  1	import * as React from 'react';
  2	import { CORSRule, GetBucketCorsCommandOutput } from '@aws-sdk/client-s3';
  3	import { getBucketOverviewBaseRoute } from '@odf/core/constants';
  4	import { S3ProviderType } from '@odf/core/types';
  5	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  6	import { CommonModalProps } from '@odf/shared/modals';
  7	import { S3Commands } from '@odf/shared/s3';
  8	import { isNoCorsRuleError } from '@odf/shared/s3/utils';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { deepSortObject } from '@odf/shared/utils';
 11	import { murmur3 } from 'murmurhash-js';
 12	import { useNavigate } from 'react-router-dom-v5-compat';
 13	import { KeyedMutator } from 'swr';
 14	import {
 15	  Modal,
 16	  ModalVariant,
 17	  Button,
 18	  ButtonVariant,
 19	} from '@patternfly/react-core';
 20	
 21	type DeleteCorsRuleModalProps = {
 22	  mutate: KeyedMutator<GetBucketCorsCommandOutput>;
 23	  s3Client: S3Commands;
 24	  bucketName: string;
 25	  ruleName: string;
 26	  ruleHash: number;
 27	  navigateToListPage: boolean;
 28	};
 29	
 30	const getUpdatedCorsRules = (
 31	  latestRules: GetBucketCorsCommandOutput,
 32	  ruleName: string,
 33	  ruleHash: number
 34	) => {
 35	  let filteredRules: CORSRule[];
 36	  if (!!ruleName) {
 37	    filteredRules =
 38	      latestRules?.CORSRules?.filter((rule) => rule.ID !== ruleName) || [];
 39	  } else if (!!ruleHash) {
 40	    // fallback if rule name (ID) is missing
 41	    filteredRules =
 42	      latestRules?.CORSRules?.filter(
 43	        (rule) => murmur3(JSON.stringify(deepSortObject(rule))) !== ruleHash
 44	      ) || [];
 45	  } else {
 46	    filteredRules = latestRules?.CORSRules || [];
 47	  }
 48	
 49	  return filteredRules;
 50	};
 51	
 52	const DeleteCorsRuleModal: React.FC<
 53	  CommonModalProps<DeleteCorsRuleModalProps>
 54	> = ({
 55	  closeModal,
 56	  isOpen,
 57	  extraProps: {
 58	    s3Client,
 59	    bucketName,
 60	    mutate,
 61	    ruleName,
 62	    ruleHash,
 63	    navigateToListPage,
 64	  },
 65	}) => {
 66	  const { t } = useCustomTranslation();
 67	
 68	  const navigate = useNavigate();
 69	
 70	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 71	  const [error, setError] = React.useState<Error>();
 72	
 73	  const providerType = s3Client.providerType as S3ProviderType;
 74	
 75	  const onDelete = async (event) => {
 76	    event.preventDefault();
 77	    setInProgress(true);
 78	
 79	    try {
 80	      let latestRules: GetBucketCorsCommandOutput;
 81	
 82	      try {
 83	        latestRules = await s3Client.getBucketCors({ Bucket: bucketName });
 84	      } catch (err) {
 85	        if (isNoCorsRuleError(err)) {
 86	          latestRules = { CORSRules: [] } as GetBucketCorsCommandOutput;
 87	        } else {
 88	          throw err;
 89	        }
 90	      }
 91	
 92	      // `{ CORSConfiguration: { CORSRules: [] } }` syntax is being interpreted as an attempt to update CORS config (not delete) with an invalid payload (no rules),
 93	      // so the endpoint is throwing a 500 error.
 94	      // Hence using "deleteBucketCors" for such cases where we need to cleanup entire CORS configuration.
 95	      const updatedCorsRules = getUpdatedCorsRules(
 96	        latestRules,
 97	        ruleName,
 98	        ruleHash
 99	      );
100	      if (!!updatedCorsRules?.length)
101	        await s3Client.putBucketCors({
102	          Bucket: bucketName,
103	          CORSConfiguration: {
104	            CORSRules: updatedCorsRules,
105	          },
106	        });
107	      else await s3Client.deleteBucketCors({ Bucket: bucketName });
108	
109	      setInProgress(false);
110	      mutate();
111	      closeModal();
112	      navigateToListPage &&
113	        navigate(
114	          `${getBucketOverviewBaseRoute(bucketName, providerType)}/permissions/cors`
115	        );
116	    } catch (err) {
117	      setInProgress(false);
118	      setError(err);
119	    }
120	  };
121	
122	  return (
123	    <Modal
124	      title={t('Delete CORS rule?')}
125	      titleIconVariant="warning"
126	      isOpen={isOpen}
127	      onClose={closeModal}
128	      variant={ModalVariant.medium}
129	      actions={[
130	        <ButtonBar
131	          inProgress={inProgress}
132	          errorMessage={error?.message || JSON.stringify(error)}
133	        >
134	          <span>
135	            <Button
136	              variant={ButtonVariant.danger}
137	              onClick={onDelete}
138	              isDisabled={!!error || inProgress}
139	              className="pf-v6-u-mr-xs"
140	            >
141	              {t('Delete')}
142	            </Button>
143	            <Button
144	              variant={ButtonVariant.link}
145	              onClick={closeModal}
146	              className="pf-v6-u-ml-xs"
147	            >
148	              {t('Cancel')}
149	            </Button>
150	          </span>
151	        </ButtonBar>,
152	      ]}
153	    >
154	      {' '}
155	    </Modal>
156	  );
157	};
158	
159	export default DeleteCorsRuleModal;

